const inputData = $input.all()[0].json;

// Récupère la langue de l'utilisateur (par défaut : français)
const userLanguage = inputData.user_language || 'fr';
const languageInstruction = userLanguage === 'en' 
  ? 'Respond in English.' 
  : 'Réponds en français.';

const payload = {
  model: "gpt-4o",
  messages: [
    {
      role: "system",
      content: `Tu es un expert RH spécialisé en analyse de CV.

${languageInstruction}

IMPORTANT : Retourne UNIQUEMENT un objet JSON valide avec cette structure EXACTE (sans backticks markdown) :

{
  "candidate_name": "${userLanguage === 'en' ? 'Candidate First and Last Name extracted from CV' : 'Prénom NOM du candidat extrait du CV'}",
  "matching_score": 85,
  "strengths": ["${userLanguage === 'en' ? 'Strength 1' : 'Force 1'}", "${userLanguage === 'en' ? 'Strength 2' : 'Force 2'}", "${userLanguage === 'en' ? 'Strength 3' : 'Force 3'}"],
  "weaknesses": ["${userLanguage === 'en' ? 'Weakness 1' : 'Faiblesse 1'}", "${userLanguage === 'en' ? 'Weakness 2' : 'Faiblesse 2'}"],
  "recommendation": "${userLanguage === 'en' ? 'Detailed recommendation' : 'Recommandation détaillée'}",
  "key_insights": ["${userLanguage === 'en' ? 'Insight 1' : 'Insight 1'}", "${userLanguage === 'en' ? 'Insight 2' : 'Insight 2'}"],
  "interview_questions": ["${userLanguage === 'en' ? 'Question 1' : 'Question 1'}", "${userLanguage === 'en' ? 'Question 2' : 'Question 2'}"]
}

Ne retourne RIEN d'autre que ce JSON pur.`
    },
    {
      role: "user",
      content: `${userLanguage === 'en' ? 'Analyze this CV against the job offer:' : 'Analyse ce CV par rapport à l\'offre d\'emploi :'}

${userLanguage === 'en' ? 'CANDIDATE CV:' : 'CV DU CANDIDAT :'}
${inputData.cv_text ? inputData.cv_text.substring(0, 4000) : (userLanguage === 'en' ? 'CV not available' : 'CV non disponible')}

${userLanguage === 'en' ? 'JOB OFFER:' : 'OFFRE D\'EMPLOI :'}
${inputData.job_url}

${userLanguage === 'en' ? 'Job description (raw HTML):' : 'Description de l\'offre (HTML brut) :'}
${typeof inputData.job_data === 'string' ? inputData.job_data.substring(0, 2000) : JSON.stringify(inputData.job_data).substring(0, 2000)}

${userLanguage === 'en' ? 'Return your analysis in pure JSON format (without markdown).' : 'Retourne ton analyse au format JSON pur (sans markdown).'}`
    }
  ],
  temperature: 0.3,
  max_tokens: 1500
};

return [{
  json: {
    mammouthPayload: payload,
    user_language: userLanguage,  // Propage la langue
    debugInfo: {
      timestamp: new Date().toISOString(),
      cv_length: inputData.cv_text?.length || 0,
      job_url: inputData.job_url,
      language: userLanguage
    }
  }
}];

const analysis = $input.item.json;
const cvText = analysis.cv_text || '';
const jobData = analysis.job_data || '';

// Validation de la longueur
if (cvText.length < 200 || jobData.length < 200) {
  return {
    json: {
      validation_status: "input_error",
      error_message: `CV ou offre trop court(e) (< 200 caractères)`,
      cv_text: cvText,
      job_data: jobData,
      user_language: analysis.user_language // Propage la langue
    }
  };
}

// Ajoute les champs manquants
const finalAnalysis = {
  ...analysis,
  cv_text: cvText,
  job_data: jobData,
  user_email: analysis.user_email,
  user_language: analysis.user_language, // Propage la langue
  analyzed_at: new Date().toISOString(),
  validation_status: "success",
  analysis_type: "cv_screening"
};

return {
  json: finalAnalysis
};

// Récupère le HTML brut du nœud précédent
const html = $input.item.json.data;

// Fonction simple pour enlever les balises HTML et nettoyer le texte
function stripHtml(htmlString) {
  if (!htmlString) {
    return '';
  }
  // Enlève les scripts, styles, et commentaires
  let cleaned = htmlString.replace(/<script[^>]*>([\S\s]*?)<\/script>/gmi, '');
  cleaned = cleaned.replace(/<style[^>]*>([\S\s]*?)<\/style>/gmi, '');
  cleaned = cleaned.replace(/<!--[\s\S]*?-->/g, '');
  // Remplace les balises par des espaces et décode les entités HTML
  cleaned = cleaned.replace(/<[^>]+>/g, ' ').replace(/&nbsp;/g, ' ');
  // Supprime les espaces multiples et les lignes vides
  cleaned = cleaned.replace(/\s\s+/g, ' ').trim();
  return cleaned;
}

const jobText = stripHtml(html);

console.log(`Longueur du texte de l'offre : ${jobText.length}`);

// Retourne les données de l'offre et l'URL d'origine
return {
  json: {
    job_url: $input.item.json.job_url, // Propage l'URL
    job_data: jobText,
    data: jobText // Garde "data" pour la compatibilité
  }
};

// Récupère les données du CV directement depuis sa branche
const cvNode = $node["Add Email to CV Data"];
const cvData = cvNode.json;

// Récupère les données de l'offre directement depuis sa branche
const jobNode = $node["Code in JavaScript"];
const jobData = jobNode.json;

// Récupère la langue depuis Supabase
let userLanguage = 'fr';
try {
  const supabaseNode = $node["Supabase - Get User Language"];
  if (supabaseNode && supabaseNode.json && supabaseNode.json.preferred_language) {
    userLanguage = supabaseNode.json.preferred_language;
  }
} catch (error) {
  console.log('⚠️ Langue par défaut : français');
}

console.log('=== DEBUG Merge CV + Job Data ===');
console.log('user_email:', cvData.votre_email);
console.log('user_language:', userLanguage);
console.log('Job Data Length:', (jobData.data || jobData.job_text || '').length);

return {
  json: {
    cv_text: cvData.text || cvData.cv_text || '',
    job_url: jobData.job_url || '',
    job_data: jobData.data || jobData.job_text || '',
    user_email: cvData.votre_email || '',
    user_language: userLanguage
  }
};

console.log('=== DEBUG HTTP Request ===');
console.log('user_email:', $input.item.json.user_email);
console.log('Type:', typeof $input.item.json.user_email);
console.log('Toutes les données:', JSON.stringify($input.item.json, null, 2));

return $input.all();

// Récupère les données du formulaire
const formData = $node["Form Trigger - Upload CV"].json;

// Récupère les données du PDF
const pdfData = $input.item.json;

console.log('=== DEBUG Add Email to CV Data ===');
console.log('formData.votre_email:', formData.votre_email);
console.log('pdfData.text:', pdfData.text ? 'OK' : 'VIDE');

// Fusionne les données
return {
  json: {
    text: pdfData.text || '',
    cv_text: pdfData.text || '',
    votre_email: formData.votre_email || '',
    // Propage aussi les autres champs du PDF si nécessaire
    numpages: pdfData.numpages,
    numrender: pdfData.numrender,
    info: pdfData.info,
    version: pdfData.version
  }
};

// Récupère les données d'origine (AVANT l'appel à l'IA)
const originalData = $node["Prepare Mammouth Request"].json;

// Extrait la réponse JSON de l'IA depuis l'input de ce noeud
const aiResponse = $input.item.json.choices[0].message.content;

// Parse le JSON de l'IA
let parsedAnalysis = {};
try {
  // Nettoie la réponse de l'IA (supprime les ```json et ```)
  const cleanedResult = aiResponse.replace(/```json/g, '').replace(/```/g, '').trim();
  parsedAnalysis = JSON.parse(cleanedResult);
} catch (e) {
  console.log("Erreur de parsing JSON de l'IA", e);
  parsedAnalysis = { error: "Invalid JSON from AI" };
}

// Fusionne les données d'origine avec les données de l'IA
const mergedData = { ...originalData, ...parsedAnalysis };

// Retourne les données fusionnées
return {
  json: mergedData
};

const puppeteer = require('puppeteer');

// Récupère l'URL de l'offre depuis le nœud précédent
const jobUrl = $input.item.json.url_de_l_offre_d_emploi;

// Fonction asynchrone pour scraper avec Puppeteer
async function scrapeWithPuppeteer(url) {
  let browser = null;
  try {
    // Lance le navigateur en mode headless
    // L'argument '--no-sandbox' est souvent nécessaire dans les environnements conteneurisés
    browser = await puppeteer.launch({
      headless: true,
      args: ['--no-sandbox', '--disable-setuid-sandbox']
    });

    const page = await browser.newPage();

    // Se faire passer pour un navigateur normal
    await page.setUserAgent('Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36');

    // Navigue vers l'URL et attend que la page soit complètement chargée
    await page.goto(url, { waitUntil: 'networkidle2', timeout: 30000 });

    // Attend un sélecteur spécifique à la page de l'offre pour être sûr que le contenu est là
    // Par exemple, pour Welcome to the Jungle, on peut attendre la section de description.
    // (Ce sélecteur peut avoir besoin d'être ajusté si le site change)
    await page.waitForSelector('main', { timeout: 10000 });

    // Récupère le contenu HTML complet de la page
    const content = await page.content();

    return content;

  } catch (error) {
    console.error(`Erreur de scraping avec Puppeteer pour l'URL : ${url}`, error.message);
    return ""; // Retourne une chaîne vide en cas d'erreur
  } finally {
    // Ferme le navigateur dans tous les cas
    if (browser) {
      await browser.close();
    }
  }
}

// Exécute la fonction de scraping
const htmlContent = await scrapeWithPuppeteer(jobUrl);

// Fonction simple pour nettoyer le HTML (la même qu'avant)
function stripHtml(htmlString) {
  if (!htmlString) return '';
  let cleaned = htmlString.replace(/<script[^>]*>([\S\s]*?)<\/script>/gmi, '');
  cleaned = cleaned.replace(/<style[^>]*>([\S\s]*?)<\/style>/gmi, '');
  cleaned = cleaned.replace(/<!--[\s\S]*?-->/g, '');
  cleaned = cleaned.replace(/<[^>]+>/g, ' ').replace(/&nbsp;/g, ' ');
  cleaned = cleaned.replace(/\s\s+/g, ' ').trim();
  return cleaned;
}

const jobText = stripHtml(htmlContent);

console.log(`Scraping terminé. Longueur du texte de l'offre : ${jobText.length}`);

// Retourne les données de l'offre et l'URL d'origine
return {
  json: {
    job_url: jobUrl,
    data: jobText
  }
};
